/// <summary>
/// This class is an extension of form InventJournalLossProfit datasource InventJournalTrans
/// </summary>
[ExtensionOf(formDataSourceStr(InventJournalLossProfit, InventJournalTrans))]
internal final class ETGInventJournalLossProfit_InventJournalTrans_Extension
{

}

Method.Source:
/// <summary>
/// Calling allowEditNew method in init method
/// </summary>
void init()
{
    next init();
    this.allowEditNew();
}

/// <summary>
/// Calling allowEditNew method in active method
/// </summary>
/// <returns>int.</returns>
int active()
{
    int ret =  next active();
    this.allowEditNew();

    //CS - BIN Qty Status activation - Abhinav
    FormPartControl formpartcontrol = this.formRun().design().controlName("ETGBinQtyAvailable");
    formpartcontrol.visible(ETGCanadaParameters::find().EnableBinQtyStatus);
    InventJournalTrans InventJournalTrans = this.cursor();
    if(ETGCanadaParameters::find().EnableBinQtyStatus)
    {
        InventDim inventdim = InventJournalTrans.inventDim();
        ETGBinQtyVisualChartHelperClass::populateBinQtyChartData(inventdim,formpartcontrol);
    }
    //CE

    return ret;
}

/// <summary>
/// This method contain the logic for adding/deleting lines in inventjournal line level.
/// when flag is yes.
/// </summary>
public void allowEditNew()
{
    if(SalesParameters::find().ETGEnableCylinderTracking)
    {
        if(element.InventJournalTable.ETGConversionToInventory == NoYes::Yes)
        {
            this.formRun().design().viewEditMode(ViewEditMode::View);
            this.object(fieldNum(InventJournalTrans, Qty)).allowEdit(false);
            this.object(fieldNum(InventJournalTrans, CostPrice)).allowEdit(false);
            this.object(fieldNum(InventJournalTrans, ETGReasonId)).mandatory(false);
            this.allowCreate(false);
            this.allowDelete(false);
            this.allowEdit(false);
            this.object(fieldNum(InventJournalTrans, ETGIssueReceive)).visible(false);
            this.object(fieldNum(InventJournalTrans, ETGAlternateUOM)).visible(false);
            this.object(fieldNum(InventJournalTrans, ETGAlternateQuantity)).visible(false);
            this.object(fieldNum(InventJournalTrans, ETGAssetId)).visible(true);
        }

        InventJournalName   inventJournalName  = InventJournalName::find(element.InventJournalTable.JournalNameId);

        if(inventJournalName.ETGManualAdditionorDeletion == NoYes::Yes)
        {
            this.object(fieldNum(InventJournalTrans, ETGIssueReceive)).visible(true);
            this.object(fieldNum(InventJournalTrans, ETGAlternateUOM)).visible(true);
            this.object(fieldNum(InventJournalTrans, ETGAlternateQuantity)).visible(true);
            this.object(fieldNum(InventJournalTrans, ETGAssetId)).visible(true);

        }
        else
        {
            this.object(fieldNum(InventJournalTrans, ETGIssueReceive)).visible(false);
            this.object(fieldNum(InventJournalTrans, ETGAlternateUOM)).visible(false);
            this.object(fieldNum(InventJournalTrans, ETGAlternateQuantity)).visible(false);
            this.object(fieldNum(InventJournalTrans, ETGAssetId)).visible(false);
        }
    }

    else
    {
        this.object(fieldNum(InventJournalTrans, ETGIssueReceive)).visible(false);
        this.object(fieldNum(InventJournalTrans, ETGAlternateUOM)).visible(false);
        this.object(fieldNum(InventJournalTrans, ETGAlternateQuantity)).visible(false);
        this.object(fieldNum(InventJournalTrans, ETGAssetId)).visible(false);
    }
}
